const MAX_FONT_SIZE=30,MAX_IMAGE_BASE_SIZE=96,RELATIVE_SIZE=MAX_FONT_SIZE/MAX_IMAGE_BASE_SIZE;function getInitialsFontSize(r){if(r<=16)return 5;if(r<=24)return 8;if(r<=32)return 10;if(r<=36)return 13;if(r<=44)return 14;if(r<=48)return 17;if(r<56)return 18;if(r<=64)return 21;if(r<=88)return 26;if(r<=MAX_IMAGE_BASE_SIZE)return MAX_FONT_SIZE;r=Math.ceil(r*RELATIVE_SIZE);return r+r%2}export{getInitialsFontSize};